import{_ as e,a as n,b as i}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as t,o,c as l,a2 as r}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Ověřování a správa přihlášených zařízení","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/Safety/authentication-and-login-devices.md","filePath":"cs-CZ/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),s={name:"cs-CZ/Safety/authentication-and-login-devices.md"};function p(d,a,h,u,v,c){return o(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="overovani-a-sprava-prihlasenych-zarizeni" tabindex="-1">Ověřování a správa přihlášených zařízení <a class="header-anchor" href="#overovani-a-sprava-prihlasenych-zarizeni" aria-label="Permalink to &quot;Ověřování a správa přihlášených zařízení&quot;">​</a></h1><p><code>Authentication Management</code> a <code>Login Device Management</code> chrání administraci ImgBed, veřejný vstup pro nahrávání a přístup WebDAV.</p><p>Na této stránce nastavíte přístupové údaje, zkontrolujete přihlášená zařízení a podle potřeby zneplatníte staré relace.</p><h2 id="kde-nastavit" tabindex="-1">Kde nastavit <a class="header-anchor" href="#kde-nastavit" aria-label="Permalink to &quot;Kde nastavit&quot;">​</a></h2><p>Otevřete administraci a přejděte na:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings</span></span></code></pre></div><p>Stránka obsahuje dvě hlavní části:</p><ul><li>Authentication Management</li><li>Login Device Management</li></ul><p><img src="'+e+'" alt="Správa ověřování" loading="lazy"></p><h2 id="co-dela-authentication-management" tabindex="-1">Co dělá Authentication Management <a class="header-anchor" href="#co-dela-authentication-management" aria-label="Permalink to &quot;Co dělá Authentication Management&quot;">​</a></h2><p>Authentication Management ukládá přístupové údaje.</p><p>Existují dva typy:</p><ul><li>Ověření na straně uživatele</li><li>Ověření na straně administrátora</li></ul><h2 id="overeni-na-strane-uzivatele" tabindex="-1">Ověření na straně uživatele <a class="header-anchor" href="#overeni-na-strane-uzivatele" aria-label="Permalink to &quot;Ověření na straně uživatele&quot;">​</a></h2><p>Ověření na straně uživatele je heslo pro nahrávání.</p><p>Po nastavení hesla musí běžní návštěvníci zadat heslo před použitím stránky pro nahrávání. Hodí se to, když nechcete nechat veřejnou upload stránku otevřenou každému.</p><p><img src="'+n+'" alt="Přihlášení uživatele" loading="lazy"></p><h3 id="nastaveni-hesla-pro-nahravani" tabindex="-1">Nastavení hesla pro nahrávání <a class="header-anchor" href="#nastaveni-hesla-pro-nahravani" aria-label="Permalink to &quot;Nastavení hesla pro nahrávání&quot;">​</a></h3><p>Když je heslo pro nahrávání nastavené:</p><ul><li>návštěvníci ho musí zadat před použitím upload stránky.</li><li>nahrávání je dostupné až po přijetí hesla.</li><li>pokud jsou zapnuté relace zařízení na straně uživatele, ImgBed toto zařízení zaznamená.</li></ul><p>Změna hesla pro nahrávání zneplatní staré uživatelské relace. Návštěvníci musí zadat nové heslo znovu.</p><h2 id="overeni-administratora" tabindex="-1">Ověření administrátora <a class="header-anchor" href="#overeni-administratora" aria-label="Permalink to &quot;Ověření administrátora&quot;">​</a></h2><p>Ověření administrátora používá administrátorské uživatelské jméno a heslo.</p><p>Chrání administraci. V produkčním provozu by mělo být vždy nastavené.</p><p><img src="'+i+'" alt="Přihlášení administrátora" loading="lazy"></p><h3 id="nastaveni-udaju-administratora" tabindex="-1">Nastavení údajů administrátora <a class="header-anchor" href="#nastaveni-udaju-administratora" aria-label="Permalink to &quot;Nastavení údajů administrátora&quot;">​</a></h3><p>Když jsou nastavené administrátorské jméno a heslo:</p><ul><li>otevření administrace vyžaduje přihlášení.</li><li>úspěšné přihlášení vytvoří záznam administrátorského zařízení.</li><li>zařízení můžete kontrolovat, čistit nebo vynutit offline v Login Device Management.</li></ul><p>Změna administrátorského jména nebo hesla zneplatní staré administrátorské relace. Musíte se přihlásit znovu.</p><h2 id="co-dela-login-device-management" tabindex="-1">Co dělá Login Device Management <a class="header-anchor" href="#co-dela-login-device-management" aria-label="Permalink to &quot;Co dělá Login Device Management&quot;">​</a></h2><p>Login Device Management ukazuje zařízení, která se přihlásila.</p><p>Pomáhá zkontrolovat:</p><ul><li>která zařízení přistupovala do administrace.</li><li>která zařízení používala upload stránku na straně uživatele.</li><li>kteří WebDAV klienti se připojili.</li><li>zda je relace zařízení stále platná.</li><li>zda je potřeba stará zařízení vynutit offline.</li></ul><p>Stránka má tři karty:</p><ul><li>Admin</li><li>User</li><li>WebDAV</li></ul><h2 id="globalni-zabezpeceni-cookies" tabindex="-1">Globální zabezpečení cookies <a class="header-anchor" href="#globalni-zabezpeceni-cookies" aria-label="Permalink to &quot;Globální zabezpečení cookies&quot;">​</a></h2><p>V horní části Login Device Management můžete nastavit globální chování cookies.</p><h3 id="zivotnost-cookie-uzivatele" tabindex="-1">Životnost cookie uživatele <a class="header-anchor" href="#zivotnost-cookie-uzivatele" aria-label="Permalink to &quot;Životnost cookie uživatele&quot;">​</a></h3><p>Určuje, kolik dní zůstane přihlášení na straně uživatele aktivní.</p><p>Například při nastavení na 14 dní návštěvníci obvykle nemusí znovu zadávat heslo pro nahrávání po dobu 14 dní.</p><h3 id="zivotnost-cookie-administratora" tabindex="-1">Životnost cookie administrátora <a class="header-anchor" href="#zivotnost-cookie-administratora" aria-label="Permalink to &quot;Životnost cookie administrátora&quot;">​</a></h3><p>Určuje, kolik dní zůstane administrátorské přihlášení aktivní.</p><p>Například při nastavení na 14 dní se administrátoři obvykle nemusí znovu přihlašovat po dobu 14 dní.</p><h3 id="secure-mode" tabindex="-1">Secure Mode <a class="header-anchor" href="#secure-mode" aria-label="Permalink to &quot;Secure Mode&quot;">​</a></h3><p>Když je Secure mode zapnutý, prohlížeče posílají přihlašovací cookies pouze přes HTTPS.</p><p>Zapněte ho pro produkční HTTPS weby. Nezapínejte ho při lokálním HTTP testování, jinak můžete vidět chování typu „přihlášení proběhlo, ale po obnovení jsem odhlášený“.</p><h2 id="administratorska-prihlasena-zarizeni" tabindex="-1">Administrátorská přihlášená zařízení <a class="header-anchor" href="#administratorska-prihlasena-zarizeni" aria-label="Permalink to &quot;Administrátorská přihlášená zařízení&quot;">​</a></h2><p>Karta Admin ukazuje zařízení, která se přihlásila do administrace.</p><p>Záznamy zařízení se zobrazují až po nastavení administrátorských údajů a po přístupu do administrace přes přihlášení.</p><p>Každá karta zařízení může ukazovat:</p><ul><li>informace o zařízení a prohlížeči</li><li>IP prvního přihlášení</li><li>IP poslední aktivity</li><li>čas přihlášení</li><li>čas poslední aktivity</li><li>čas vypršení</li><li>aktuální stav</li></ul><p>Pokud vidíte neznámé zařízení, použijte <code>Force Offline</code> pro zneplatnění relace.</p><h2 id="vycisteni-starych-zarizeni" tabindex="-1">Vyčištění starých zařízení <a class="header-anchor" href="#vycisteni-starych-zarizeni" aria-label="Permalink to &quot;Vyčištění starých zařízení&quot;">​</a></h2><p><code>Clean Up Old Devices</code> hromadně odstraní staré záznamy přihlášení na aktuální kartě.</p><p>Použijte to, když máte podezření, že staré relace mohou být stále aktivní na jiných zařízeních.</p><h2 id="vynuceni-offline" tabindex="-1">Vynucení offline <a class="header-anchor" href="#vynuceni-offline" aria-label="Permalink to &quot;Vynucení offline&quot;">​</a></h2><p><code>Force Offline</code> zneplatní jednu relaci zařízení.</p><p>Po vynucení offline:</p><ul><li>administrátorská zařízení se musí znovu přihlásit.</li><li>uživatelská zařízení musí znovu zadat heslo pro nahrávání.</li><li>WebDAV klienti se musí znovu ověřit.</li></ul><p>Vypršená nebo neplatná zařízení lze také odstranit.</p><h2 id="odhlaseni-aktualniho-zarizeni" tabindex="-1">Odhlášení aktuálního zařízení <a class="header-anchor" href="#odhlaseni-aktualniho-zarizeni" aria-label="Permalink to &quot;Odhlášení aktuálního zařízení&quot;">​</a></h2><p>Karta aktuálního zařízení je označená jako <code>Current Device</code>.</p><p>Po odhlášení aktuálního zařízení:</p><ul><li>aktuální administrátorská relace se odhlásí.</li><li>aktuální uživatelská relace se odhlásí.</li></ul><p>Před dalším používáním dané části je potřeba se znovu přihlásit.</p>',65)])])}const b=t(s,[["render",p]]);export{k as __pageData,b as default};
